from abc import ABC, abstractmethod

# Product
class Car:
    def __init__(self):
        self.engine = None
        self.wheels = None
        self.color = None
        self.has_gps = False

    def __str__(self):
        return (f"Car Details:\n"
                f"  Engine: {self.engine}\n"
                f"  Wheels: {self.wheels}\n"
                f"  Color: {self.color}\n"
                f"  GPS: {'Yes' if self.has_gps else 'No'}")

# Abstract Builder
class CarBuilder(ABC):
    def __init__(self):
        self._car = Car()

    @abstractmethod
    def set_engine(self):
        pass

    @abstractmethod
    def set_wheels(self):
        pass

    @abstractmethod
    def set_color(self):
        pass

    @abstractmethod
    def set_gps(self):
        pass

    def get_car(self) -> Car:
        return self._car

# Concrete Builders
class SportsCarBuilder(CarBuilder):
    def set_engine(self):
        self._car.engine = "V8 Turbo"
        return self # For fluent interface

    def set_wheels(self):
        self._car.wheels = "19-inch Alloy"
        return self

    def set_color(self):
        self._car.color = "Red"
        return self

    def set_gps(self):
        self._car.has_gps = True
        return self

class SUVCarBuilder(CarBuilder):
    def set_engine(self):
        self._car.engine = "V6 Diesel"
        return self

    def set_wheels(self):
        self._car.wheels = "18-inch Off-road"
        return self

    def set_color(self):
        self._car.color = "Black"
        return self

    def set_gps(self):
        self._car.has_gps = False # SUVs might not always need GPS, or it's an option
        return self

# Director
class CarManufacturingDirector:
    def construct_sports_car(self, builder: CarBuilder) -> Car:
        return builder.set_engine().set_wheels().set_color().set_gps().get_car()

    def construct_suv(self, builder: CarBuilder) -> Car:
        return builder.set_engine().set_wheels().set_color().set_gps().get_car()

    def construct_custom_car(self, builder: CarBuilder, engine, wheels, color, has_gps) -> Car:
        # Example of allowing more granular control through the director or directly
        builder.set_engine(); builder._car.engine = engine
        builder.set_wheels(); builder._car.wheels = wheels
        builder.set_color(); builder._car.color = color
        builder.set_gps(); builder._car.has_gps = has_gps
        return builder.get_car()


if __name__ == "__main__":
    director = CarManufacturingDirector()

    # Build a Sports Car
    sports_car_builder = SportsCarBuilder()
    sports_car = director.construct_sports_car(sports_car_builder)
    print("--- Sports Car ---")
    print(sports_car)
    print("\n")

    # Build an SUV
    suv_builder = SUVCarBuilder()
    suv = director.construct_suv(suv_builder)
    print("--- SUV ---")
    print(suv)
    print("\n")

    # Build a custom car directly using the builder (without director's full pre-defined logic)
    # This shows the flexibility of the builder pattern.
    custom_builder = SportsCarBuilder() # Can start with any builder, then customize
    custom_car = custom_builder \
        .set_engine() \
        ._car.engine = "Electric Motor" # Overwriting default engine from SportsCarBuilder
    custom_car = custom_builder \
        .set_wheels() \
        ._car.wheels = "20-inch Aero" # Overwriting default wheels
    custom_car = custom_builder \
        .set_color() \
        ._car.color = "Silver"
    custom_car = custom_builder \
        .set_gps() \
        ._car.has_gps = True
    custom_car = custom_builder.get_car()

    print("--- Custom Car ---")
    print(custom_car)
